import{_ as l,C as c,o as r,c as g,a2 as o,b as a,w as e,a as s,E as n,a3 as i}from"./chunks/framework.c3r8iWL8.js";const S=JSON.parse('{"title":"Guide: Identity, Access & Secrets","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/identity-access-secrets.md","filePath":"guides/identity-access-secrets.md","lastUpdated":1782929962000}'),h={name:"guides/identity-access-secrets.md"};function p(m,t,u,y,b,f){const d=c("Mermaid");return r(),g("div",null,[t[2]||(t[2]=o('<h1 id="guide-identity-access-secrets" tabindex="-1">Guide: Identity, Access &amp; Secrets <a class="header-anchor" href="#guide-identity-access-secrets" aria-label="Permalink to &quot;Guide: Identity, Access &amp; Secrets&quot;">​</a></h1><p><strong>Decision:</strong> How humans, CI, and services authenticate — and how credentials, keys, and permissions are scoped across environments.</p><p>Related: <a href="./../identity-access-secrets.html">identity-access-secrets.md</a> · <a href="./data-governance.html">data-governance.md</a> · <a href="./ci-cd-release.html">ci-cd-release.md</a> · <a href="./static-analysis-linting.html">static-analysis-linting.md</a> · <a href="./ai-guardrails-security.html">ai-guardrails-security.md</a> · <a href="./../sops/SOP-010-ai-tool-usage.html">SOP-010</a> · <a href="./../sops/SOP-011-onboarding.html">SOP-011</a> · <a href="./../GOVERNANCE.html">GOVERNANCE</a></p><hr><h2 id="scope-three-access-planes" tabindex="-1">Scope: three access planes <a class="header-anchor" href="#scope-three-access-planes" aria-label="Permalink to &quot;Scope: three access planes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Plane</th><th>Who</th><th>Typical controls</th><th>This guide section</th></tr></thead><tbody><tr><td><strong>Human (workforce)</strong></td><td>Developers, SRE, SEC, PO</td><td>SSO, IAM Identity Center, break-glass</td><td><a href="#workforce-identity-sso--iam">Workforce identity</a></td></tr><tr><td><strong>Machine (CI/CD &amp; workloads)</strong></td><td>Pipelines, ECS tasks, Lambda</td><td>OIDC, IAM roles, IRSA</td><td><a href="#cicd--runtime-iam">CI/CD &amp; runtime IAM</a></td></tr><tr><td><strong>Application (end users)</strong></td><td>Customers, internal users</td><td>RBAC, ABAC, API scopes</td><td><a href="#application-rbac">Application RBAC</a></td></tr></tbody></table><p><strong>Secret scanning</strong> (detecting keys in Git) lives in <a href="./static-analysis-linting.html">Linters &amp; static analysis</a>. This guide covers <strong>storage, rotation, access, and permission design</strong>.</p><hr><h2 id="workforce-identity-sso-→-iam" tabindex="-1">Workforce identity (SSO → IAM) <a class="header-anchor" href="#workforce-identity-sso-→-iam" aria-label="Permalink to &quot;Workforce identity (SSO → IAM)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>IAM Identity Center (SSO) + permission sets</strong></td><td>Central IdP federation; per-account roles</td><td>Permission-set sprawl without governance</td></tr><tr><td><strong>Direct IAM users</strong></td><td>Simple for tiny teams</td><td>No SSO; keys on laptops; audit nightmare</td></tr><tr><td><strong>Cross-account role assumption</strong></td><td>Clear dev/staging/prod separation</td><td>Trust policy mistakes = lateral movement</td></tr><tr><td><strong>Just-in-time (JIT) elevation</strong></td><td>Reduces standing prod access</td><td>Extra tooling (e.g. IAM Identity Center + approval workflow)</td></tr></tbody></table><p><strong>Recommended:</strong> IAM Identity Center → permission sets mapped to <strong>environment accounts</strong> (dev / staging / prod). No long-lived access keys for humans.</p><h3 id="environment-account-pattern" tabindex="-1">Environment account pattern <a class="header-anchor" href="#environment-account-pattern" aria-label="Permalink to &quot;Environment account pattern&quot;">​</a></h3>',12)),(r(),a(i,null,{default:e(()=>[n(d,{id:"mermaid-149",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20IDP%5BCorporate%20IdP%5D%20--%3E%20IC%5BIAM%20Identity%20Center%5D%0A%20%20%20%20IC%20--%3E%20DEV%5BDev%20account%5D%0A%20%20%20%20IC%20--%3E%20STG%5BStaging%20account%5D%0A%20%20%20%20IC%20--%3E%20PRD%5BProd%20account%5D%0A%20%20%20%20DEV%20--%3E%20PS_DEV%5BPermission%20set%3A%20Developer%5D%0A%20%20%20%20STG%20--%3E%20PS_STG%5BPermission%20set%3A%20Deployer%20read-only%5D%0A%20%20%20%20PRD%20--%3E%20PS_PRD%5BPermission%20set%3A%20SRE%20%2B%20break-glass%5D%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=o('<table tabindex="0"><thead><tr><th>Permission set (example)</th><th>Dev</th><th>Staging</th><th>Prod</th></tr></thead><tbody><tr><td><strong>Developer</strong></td><td>Read/write app resources</td><td>Read-only + deploy via CI only</td><td>No direct access</td></tr><tr><td><strong>SRE / Platform</strong></td><td>Full infra read</td><td>Deploy + observability</td><td>Deploy + incident break-glass</td></tr><tr><td><strong>Security (SEC)</strong></td><td>Read + GuardDuty</td><td>Read + scan configs</td><td>Read + audit; no data plane write</td></tr><tr><td><strong>Read-only auditor</strong></td><td>Read</td><td>Read</td><td>Read</td></tr></tbody></table><p><strong>Pitfall:</strong> Developers with <code>AdministratorAccess</code> in prod &quot;for debugging&quot; — use read-only + temporary elevation with ticket audit.</p><hr><h2 id="ci-cd-runtime-iam" tabindex="-1">CI/CD &amp; runtime IAM <a class="header-anchor" href="#ci-cd-runtime-iam" aria-label="Permalink to &quot;CI/CD &amp; runtime IAM&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>OIDC federation (GitHub Actions → AWS)</strong></td><td>No static CI keys; short-lived creds</td><td>Trust policy + audience tuning</td></tr><tr><td><strong>CodePipeline service role</strong></td><td>Native AWS; simple in-account</td><td>Cross-repo patterns harder</td></tr><tr><td><strong>Long-lived IAM user for CI</strong></td><td>Familiar</td><td><strong>Avoid</strong> — key rotation burden, leak risk</td></tr><tr><td><strong>Task/instance roles (ECS, EKS IRSA, Lambda)</strong></td><td>Least privilege per workload</td><td>Policy per service; needs IaC discipline</td></tr><tr><td><strong>ABAC via resource tags</strong></td><td>Scales multi-team accounts</td><td>Tag hygiene; policy complexity</td></tr></tbody></table><p><strong>Recommended:</strong> One org standard — <strong>OIDC for external CI</strong> (GitHub/GitLab) or <strong>CodePipeline roles in-account</strong>; workloads always use <strong>task roles</strong>, never instance profiles with broad <code>s3:*</code>.</p><h3 id="ci-oidc-vs-static-keys" tabindex="-1">CI OIDC vs static keys <a class="header-anchor" href="#ci-oidc-vs-static-keys" aria-label="Permalink to &quot;CI OIDC vs static keys&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>OIDC role</th><th>Static access key in CI secret</th></tr></thead><tbody><tr><td>Credential lifetime</td><td>Minutes</td><td>Until rotated (often never)</td></tr><tr><td>Blast radius on leak</td><td>Scoped to role + session</td><td>Full key permissions</td></tr><tr><td>AI-generated pipeline YAML risk</td><td>Still dangerous if role is too broad</td><td>Catastrophic</td></tr><tr><td>Setup cost</td><td>One-time trust + role</td><td>&quot;Easy&quot; day one</td></tr></tbody></table><p>See <a href="./ci-cd-release.html">CI/CD &amp; release</a> for orchestrator choice; this guide owns <strong>how CI authenticates</strong>.</p><h3 id="runtime-permission-model" tabindex="-1">Runtime permission model <a class="header-anchor" href="#runtime-permission-model" aria-label="Permalink to &quot;Runtime permission model&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Workload</th><th>Pattern</th><th>Pitfall</th></tr></thead><tbody><tr><td><strong>ECS Fargate</strong></td><td>Task execution role + task role</td><td>Task role with <code>*</code> on S3/RDS</td></tr><tr><td><strong>EKS</strong></td><td>IRSA per service account</td><td>Shared namespace SA with admin</td></tr><tr><td><strong>Lambda</strong></td><td>Function execution role</td><td>One role for all functions</td></tr><tr><td><strong>Batch / Glue</strong></td><td>Job role scoped to job prefix</td><td>Cross-job data access</td></tr></tbody></table><p><strong>With AI:</strong> Models generate IAM policies with <code>&quot;Action&quot;: &quot;*&quot;</code> — enforce <strong>OPA/Conftest</strong> on IaC (see <a href="./static-analysis-linting.html">static-analysis-linting.md</a>) and human review for new permissions.</p><hr><h2 id="application-rbac" tabindex="-1">Application RBAC <a class="header-anchor" href="#application-rbac" aria-label="Permalink to &quot;Application RBAC&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Amazon Cognito + groups → IAM (API Gateway)</strong></td><td>AWS-native; JWT at edge</td><td>Cognito UX limits for complex B2B</td></tr><tr><td><strong>Corporate IdP (Okta, Entra) + OIDC/SAML app</strong></td><td>Single sign-on for workforce apps</td><td>App must map groups → roles</td></tr><tr><td><strong>Custom RBAC in app DB</strong></td><td>Flexible product roles</td><td>Easy to get wrong; test coverage critical</td></tr><tr><td><strong>ABAC (attributes: tenant, classification, region)</strong></td><td>Fine-grained multi-tenant</td><td>Policy authoring harder</td></tr><tr><td><strong>OPA / Cedar at API gateway</strong></td><td>Central policy; auditable</td><td>Latency + operational overhead</td></tr><tr><td><strong>AWS Verified Permissions (Cedar)</strong></td><td>Managed policy store</td><td>Cedar learning curve</td></tr></tbody></table><p><strong>Recommended starting point:</strong></p><ul><li><strong>Customer-facing SaaS:</strong> IdP or Cognito for auth + <strong>explicit RBAC model in ADR</strong> (roles, permissions, tenant isolation).</li><li><strong>Internal tools:</strong> Corporate SSO + group-to-role mapping.</li><li><strong>Service-to-service:</strong> mTLS or SigV4 with <strong>scoped IAM roles</strong> — not shared API keys.</li></ul><h3 id="rbac-design-checklist-record-in-adr" tabindex="-1">RBAC design checklist (record in ADR) <a class="header-anchor" href="#rbac-design-checklist-record-in-adr" aria-label="Permalink to &quot;RBAC design checklist (record in ADR)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Element</th><th>Example</th><th>Pitfall</th></tr></thead><tbody><tr><td><strong>Roles</strong></td><td><code>admin</code>, <code>editor</code>, <code>viewer</code></td><td>Role explosion (50+ roles)</td></tr><tr><td><strong>Permissions</strong></td><td><code>invoice:read</code>, <code>invoice:write</code></td><td>Coarse <code>admin</code> only</td></tr><tr><td><strong>Scope</strong></td><td>Org / tenant / resource</td><td>Missing tenant boundary → data leak</td></tr><tr><td><strong>Default deny</strong></td><td>New users = no access</td><td>Default allow in generated code</td></tr><tr><td><strong>Audit</strong></td><td>Who granted role change</td><td>No log on privilege escalation</td></tr></tbody></table><p><strong>With AI:</strong> Generated auth middleware often skips <strong>authorization</strong> while implementing <strong>authentication</strong> — require contract tests for forbidden paths per role.</p><hr><h2 id="secret-management-lifecycle" tabindex="-1">Secret management lifecycle <a class="header-anchor" href="#secret-management-lifecycle" aria-label="Permalink to &quot;Secret management lifecycle&quot;">​</a></h2><h3 id="where-secrets-live" tabindex="-1">Where secrets live <a class="header-anchor" href="#where-secrets-live" aria-label="Permalink to &quot;Where secrets live&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Store</th><th>Best for</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Secrets Manager</strong></td><td>DB passwords, API keys, rotation</td><td>Automatic rotation hooks</td><td>Cost per secret</td></tr><tr><td><strong>SSM Parameter Store (SecureString)</strong></td><td>Config + non-rotating secrets</td><td>Cheaper; KMS-backed</td><td>Rotation manual unless scripted</td></tr><tr><td><strong>KMS envelope encryption</strong></td><td>App-level secret blobs</td><td>Strong audit</td><td>App must call KMS</td></tr><tr><td><strong>Git / <code>.env</code> in repo</strong></td><td>—</td><td>—</td><td><strong>Never</strong> (scan + block)</td></tr><tr><td><strong>CI variables (masked)</strong></td><td>Build-time only</td><td>Simple</td><td>Leak via logs; not for prod DB passwords in app</td></tr></tbody></table><p><strong>Recommended:</strong> Secrets Manager for <strong>rotating credentials</strong>; Parameter Store for <strong>static config</strong>; <strong>never</strong> plaintext in Git, tickets, or AI prompts (<a href="./../sops/SOP-010-ai-tool-usage.html">SOP-010</a>).</p><h3 id="lifecycle-stages" tabindex="-1">Lifecycle stages <a class="header-anchor" href="#lifecycle-stages" aria-label="Permalink to &quot;Lifecycle stages&quot;">​</a></h3>',26)),(r(),a(i,null,{default:e(()=>[n(d,{id:"mermaid-730",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20CREATE%5BCreate%20in%20SM%2FSSM%5D%20--%3E%20BIND%5BBind%20to%20task%20role%20only%5D%0A%20%20%20%20BIND%20--%3E%20USE%5BRuntime%20fetch%20%E2%80%94%20no%20env%20in%20image%5D%0A%20%20%20%20USE%20--%3E%20ROT%5BRotate%20on%20schedule%2Fevent%5D%0A%20%20%20%20ROT%20--%3E%20REV%5BRevoke%20old%20version%5D%0A%20%20%20%20REV%20--%3E%20AUD%5BCloudTrail%20audit%5D%0A"})]),fallback:e(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=o('<table tabindex="0"><thead><tr><th>Stage</th><th>Control</th><th>Owner</th></tr></thead><tbody><tr><td><strong>Create</strong></td><td>Naming convention <code>{env}/{service}/{name}</code></td><td>SRE + service owner</td></tr><tr><td><strong>Read</strong></td><td>IAM <code>secretsmanager:GetSecretValue</code> on resource ARN</td><td>Task role only</td></tr><tr><td><strong>Rotate</strong></td><td>Lambda rotation or native RDS rotation</td><td>SRE</td></tr><tr><td><strong>Break-glass</strong></td><td>Separate emergency secret; time-bound access</td><td>SEC + SRE</td></tr><tr><td><strong>Detect leak</strong></td><td>gitleaks + GuardDuty + SM access anomalies</td><td>SEC</td></tr></tbody></table><h3 id="rotation-policy-example" tabindex="-1">Rotation policy (example) <a class="header-anchor" href="#rotation-policy-example" aria-label="Permalink to &quot;Rotation policy (example)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Secret type</th><th>Rotation</th><th>Trigger</th></tr></thead><tbody><tr><td>Database password</td><td>30–90 days</td><td>Automated SM rotation</td></tr><tr><td>Third-party API key</td><td>90 days or vendor policy</td><td>Calendar + incident</td></tr><tr><td>CI OIDC</td><td>N/A (no long-lived secret)</td><td>—</td></tr><tr><td>KMS CMK</td><td>Annual or on compromise</td><td>SEC runbook</td></tr><tr><td>JWT signing key</td><td>90 days + overlap window</td><td>Dual-key verify period</td></tr></tbody></table><p><strong>Pitfall:</strong> Rotation without <strong>dual-active period</strong> — app breaks at flip. Always support current + previous key during overlap.</p><hr><h2 id="permission-matrix-by-lifecycle-phase" tabindex="-1">Permission matrix by lifecycle phase <a class="header-anchor" href="#permission-matrix-by-lifecycle-phase" aria-label="Permalink to &quot;Permission matrix by lifecycle phase&quot;">​</a></h2><p>Maps <a href="./../GOVERNANCE.html">GOVERNANCE</a> roles to <strong>access types</strong> (not every IAM action — adapt in your ADR).</p><table tabindex="0"><thead><tr><th>Phase</th><th>Human access</th><th>CI / machine access</th><th>Application RBAC</th></tr></thead><tbody><tr><td><strong>Plan / intake</strong></td><td>PO, ARCH: backlog tools</td><td>—</td><td>—</td></tr><tr><td><strong>Define (spec, ADR)</strong></td><td>ARCH, SEC: Git write <code>docs/</code></td><td>—</td><td>—</td></tr><tr><td><strong>Build</strong></td><td>DEV: dev account write</td><td>CI: build, scan, push ECR (no prod)</td><td>Dev/test tenants only</td></tr><tr><td><strong>Verify (PR)</strong></td><td>Reviewers: Git; no prod</td><td>CI: unit/integration in ephemeral account</td><td>Test roles in preview env</td></tr><tr><td><strong>Release</strong></td><td>SRE: approve T1 deploy</td><td>CD: deploy staging → prod via scoped role</td><td>Staging sign-off roles</td></tr><tr><td><strong>Operate</strong></td><td>SRE on-call: prod read + runbook actions</td><td>Workloads: task roles only</td><td>Prod user roles enforced</td></tr><tr><td><strong>Incident</strong></td><td>IC: break-glass (logged)</td><td>Rollback pipeline role</td><td>May disable features via flags</td></tr><tr><td><strong>Learn</strong></td><td>Postmortem: log/metric read</td><td>—</td><td>—</td></tr></tbody></table><h3 id="deploy-permission-split-recommended" tabindex="-1">Deploy permission split (recommended) <a class="header-anchor" href="#deploy-permission-split-recommended" aria-label="Permalink to &quot;Deploy permission split (recommended)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Who may trigger</th><th>AWS mechanism</th></tr></thead><tbody><tr><td>Merge to <code>main</code></td><td>DEV + reviewer + green CI</td><td>Branch protection</td></tr><tr><td>Deploy staging</td><td>CI pipeline role</td><td><code>deploy-staging</code> role</td></tr><tr><td>Deploy prod T1</td><td>SRE approval + CI</td><td><code>deploy-prod</code> role + manual gate</td></tr><tr><td>Deploy prod T2–3</td><td>CI after metric gate</td><td>Same role; no human for routine</td></tr><tr><td>IAM policy change</td><td>SRE/SEC review + IaC PR</td><td>Separate <code>iac-admin</code> role</td></tr></tbody></table><hr><h2 id="cross-cutting-controls" tabindex="-1">Cross-cutting controls <a class="header-anchor" href="#cross-cutting-controls" aria-label="Permalink to &quot;Cross-cutting controls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Purpose</th><th>Options</th></tr></thead><tbody><tr><td><strong>CloudTrail</strong></td><td>API audit</td><td>Org trail; log file validation</td></tr><tr><td><strong>IAM Access Analyzer</strong></td><td>External access findings</td><td>Enable in all accounts</td></tr><tr><td><strong>Permission boundaries</strong></td><td>Cap max permissions for roles</td><td>Platform team owns boundary policy</td></tr><tr><td><strong>SCP (Organizations)</strong></td><td>Deny list at account root</td><td>Deny <code>iam:*User*</code>, deny unapproved regions</td></tr><tr><td><strong>Session tags (ABAC)</strong></td><td><code>Project=</code>, <code>Classification=</code> on session</td><td>Pair with <a href="./data-governance.html">data governance Layer 2</a></td></tr><tr><td><strong>Secrets in AI</strong></td><td>Block <code>.env</code>, keys in prompts</td><td><a href="./../sops/SOP-010-ai-tool-usage.html">SOP-010</a></td></tr></tbody></table><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Shared prod DB password in Slack</strong></td><td>Instant breach</td><td>SM + break-glass only; DLP on chat</td></tr><tr><td><strong>One IAM role for all microservices</strong></td><td>Lateral movement</td><td>Task role per service</td></tr><tr><td><strong>CI admin role</strong></td><td>Compromised PR = prod takeover</td><td>Split build vs deploy roles</td></tr><tr><td><strong>RBAC only in UI, not API</strong></td><td>BOLA/IDOR via direct API</td><td>Contract tests per role</td></tr><tr><td><strong>Secrets in container env at build</strong></td><td>Image layer leak</td><td>Fetch at runtime from SM</td></tr><tr><td><strong>No offboarding</strong></td><td>Former employee access</td><td>SSO deprovision + SM version disable (<a href="./../sops/SOP-011-onboarding.html">SOP-011</a>)</td></tr><tr><td><strong>AI-generated <code>AKIA</code> in samples</strong></td><td>Real-looking keys merged</td><td>gitleaks + never commit (<a href="./static-analysis-linting.html">static-analysis-linting.md</a>)</td></tr><tr><td><strong>Permanent <code>AdministratorAccess</code> exception</strong></td><td>Policy theater</td><td>Time-bound <a href="./../sops/SOP-012-exception-handling.html">SOP-012</a></td></tr><tr><td><strong>Auth without authz</strong></td><td>Login works; data leaks across tenants</td><td>ADR-mandated permission matrix + tests</td></tr><tr><td><strong>Ignoring service-linked roles</strong></td><td>Blind spots in audit</td><td>Document SLR usage in runbooks</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><ol><li><strong>IAM Identity Center</strong> with dev/staging/prod accounts and permission sets (no human access keys).</li><li><strong>OIDC</strong> for CI → separate <strong>build</strong> and <strong>deploy</strong> roles.</li><li><strong>Secrets Manager</strong> for DB/API secrets; <strong>task roles</strong> for runtime fetch.</li><li><strong>gitleaks</strong> pre-commit + CI (see linters guide).</li><li><strong>ADR</strong> for application RBAC model before first customer-facing API.</li><li><strong>Phase × role matrix</strong> above copied into your wiki; align with <a href="./../GOVERNANCE.html">GOVERNANCE</a> RACI.</li></ol><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../identity-access-secrets.html">Identity &amp; access (topic deep dive)</a></li><li><a href="./data-governance.html">Data governance — Layer 2 access</a> · <a href="./../perspectives/security.html">Security perspective</a></li><li><a href="./../developer-workflow.html">Developer workflow</a> · <a href="./../perspectives/devops-sre.html">DevOps perspective</a></li></ul>',22))])}const C=l(h,[["render",p]]);export{S as __pageData,C as default};
